function cutOffTree(forest) {
    if(!forest || !forest[0]) return 0;
    let m = forest.length, n = forest[0].length;
    let trees = [];

    for(let i = 0; i < m; i++)
        for(let j = 0; j < n; j++)
            if(forest[i][j] > 1)
                trees.push([forest[i][j], i, j]);

    trees.sort((a, b) => a[0] - b[0]);

    let startX = 0, startY = 0;
    let totalSteps = 0;
    for(let tree of trees){
        let [, x, y] = tree;
        let steps = bfs(forest, startX, startY, x, y);
        if(steps === -1) return -1;
        totalSteps += steps;
        startX = x;
        startY = y;
    }

    return totalSteps;
}

function bfs(forest, startX, startY, endX, endY) {
    let m = forest.length, n = forest[0].length;
    let visited = Array.from({ length: m }, () => Array(n).fill(false));
    let q = [[startX, startY, 0]];
    visited[startX][startY] = true;
    let dirs = [-1, 0, 1, 0, -1];

    while(q.length !== 0) {
        let [x, y, steps] = q.shift();
        for(let k = 0; k < 4; k++) {
            let newX = x + dirs[k], newY = y + dirs[k+1];
            if(0 <= newX && newX < m && 0 <= newY && newY < n && !visited[newX][newY] && forest[newX][newY] !== 0) {
                if(newX === endX && newY === endY)
                    return steps + 1;
                q.push([newX, newY, steps + 1]);
                visited[newX][newY] = true;
            }
        }
    }

    return -1;
}
```

    1. Traverse the matrix, adding the tree positions to a trees list.
2. Sort the trees list by tree height.
3. For each tree in the list, apply Breadth-First Search (BFS) to find the minimum steps to cut the tree from the previous tree or the starting point.
4. If any BFS returns -1, return -1, otherwise, return the sum of all steps taken in BFS.

