    ```java
import java.util.*;

public int cutOffTree(List<List<Integer>> forest) {
    if(forest.isEmpty() || forest.get(0).isEmpty()) return 0;
    int m = forest.size(), n = forest.get(0).size();
    List<int[]> trees = new ArrayList<>();

    for(int i = 0; i < m; i++)
        for(int j = 0; j < n; j++)
            if(forest.get(i).get(j) > 1)
                trees.add(new int[]{i, j});

    trees.sort((a, b) -> forest.get(a[0]).get(a[1]) - forest.get(b[0]).get(b[1]));

    int startX = 0, startY = 0;
    int totalSteps = 0;
    for(int[] tree : trees){
        int x = tree[0], y = tree[1];
        int steps = bfs(forest, startX, startY, x, y);
        if(steps == -1) return -1;
        totalSteps += steps;
        startX = x;
        startY = y;
    }

    return totalSteps;
}

private int bfs(List<List<Integer>> forest, int startX, int startY, int endX, int endY) {
    int m = forest.size(), n = forest.get(0).size();
    int[][] visited = new int[m][n];
    Queue<int[]> q = new LinkedList<>();
    q.offer(new int[]{startX, startY});
    visited[startX][startY] = 1;
    int steps = 0;
    int[] dirs = {-1, 0, 1, 0, -1};

    while(!q.isEmpty()) {
        int size = q.size();
        for(int i = 0; i < size; i++) {
            int[] cur = q.poll();
            int x = cur[0], y = cur[1];

            if(x == endX && y == endY) return steps;

            for(int k = 0; k < 4; k++) {
                int newX = x + dirs[k];
                int newY = y + dirs[k+1];
                if(newX >= 0 && newX < m && newY >= 0 && newY < n && visited[newX][newY] == 0 && forest.get(newX).get(newY) != 0) {
                    q.offer(new int[]{ newX, newY });
                    visited[newX][newY] = 1;
                }
            }
        }
        steps++;
    }

    return -1;
}
```

    1. Traverse the matrix, adding the tree positions to a trees list.
2. Sort the trees list by tree height.
3. For each tree in the list, apply Breadth-First Search (BFS) to find the minimum steps to cut the tree from the previous tree or the starting point.
4. If any BFS returns -1, return -1, otherwise, return the sum of all steps taken in BFS.
